-- Create "scheduler_request_snapshots" table
CREATE TABLE "scheduler_request_snapshots" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  "request_id" character varying NOT NULL,
  "attempt_no" bigint NOT NULL DEFAULT 1,
  "decision_id" bigint NOT NULL,
  "request_profile_json" jsonb NULL,
  "candidate_snapshot_json" jsonb NULL,
  "rejected_snapshot_json" jsonb NULL,
  "ranked_account_ids_json" jsonb NULL,
  "selected_account_id" bigint NULL,
  "selected_provider_id" bigint NULL,
  "strategy" character varying NOT NULL DEFAULT 'balanced',
  "strategy_version" character varying NOT NULL DEFAULT 'v1',
  "strategy_config_hash" character varying NOT NULL DEFAULT '',
  "strategy_weights_json" jsonb NULL,
  "compatibility_warnings_json" jsonb NULL,
  PRIMARY KEY ("id")
);
-- Create index "schedulerrequestsnapshot_decision_id" to table: "scheduler_request_snapshots"
CREATE UNIQUE INDEX "schedulerrequestsnapshot_decision_id" ON "scheduler_request_snapshots" ("decision_id");
-- Create index "schedulerrequestsnapshot_request_id_attempt_no" to table: "scheduler_request_snapshots"
CREATE UNIQUE INDEX "schedulerrequestsnapshot_request_id_attempt_no" ON "scheduler_request_snapshots" ("request_id", "attempt_no");
-- Create index "schedulerrequestsnapshot_selected_account_id_created_at" to table: "scheduler_request_snapshots"
CREATE INDEX "schedulerrequestsnapshot_selected_account_id_created_at" ON "scheduler_request_snapshots" ("selected_account_id", "created_at");
-- Create index "schedulerrequestsnapshot_strategy_created_at" to table: "scheduler_request_snapshots"
CREATE INDEX "schedulerrequestsnapshot_strategy_created_at" ON "scheduler_request_snapshots" ("strategy", "created_at");
